/** UsptBsnsRsltIdxDao.insert */
insert into uspt_bsns_rslt_idx
						(
							rslt_idx_id
							, bsns_cd
							, rslt_idx_nm
							, std_idx
							, rslt_idx_type_cd
							, creator_id
							, created_dt
							, updater_id
							, updated_dt
						)
				values	(
							#{rsltIdxId}
							, #{bsnsCd}
							, #{rsltIdxNm}
							, #{stdIdx}
							, #{rsltIdxTypeCd}
							, #{creatorId}
							, #{createdDt}
							, #{updaterId}
							, #{updatedDt}
						)

/** UsptBsnsRsltIdxDao.insertList */
insert into uspt_bsns_rslt_idx
	(
		rslt_idx_id
		, bsns_cd
		, rslt_idx_nm
		, std_idx
		, rslt_idx_type_cd
		, creator_id
		, created_dt
		, updater_id
		, updated_dt
	) values

	(
		#{item.rsltIdxId}
		, #{item.bsnsCd}
		, #{item.rsltIdxNm}
		, #{item.stdIdx}
		, #{item.rsltIdxTypeCd}
		, #{item.creatorId}
		, #{item.createdDt}
		, #{item.updaterId}
		, #{item.updatedDt}
	)

mapper.update:
/** UsptBsnsRsltIdxDao.update */
update uspt_bsns_rslt_idx
set
	updater_id		= #{updaterId}
	, updated_dt	= #{updatedDt}
	, std_idx		= ${stdIdx}
	, rslt_idx_nm	= #{rsltIdxNm}
where
	rslt_idx_id = #{rsltIdxId}
	and bsns_cd = #{bsnsCd}

